   135→export function getFieldTypeForReducer(id: ReducerID, fallback: FieldType): FieldType {
   136→  return id === ReducerID.count ||
   137→    id === ReducerID.distinctCount ||
   138→    id === ReducerID.changeCount ||
   139→    id === ReducerID.countAll
   140→    ? FieldType.number
   141→    : id === ReducerID.allIsNull || id === ReducerID.allIsZero
   142→      ? FieldType.boolean
   143→      : fallback;
   144→}
   145→
   146→export function isReducerID(id: string): id is ReducerID {
   147→  return Object.keys(ReducerID).includes(id);
   148→}
