   117→  p84 = 'p84',
   118→  p85 = 'p85',
   119→  p86 = 'p86',
   120→  p87 = 'p87',
   121→  p88 = 'p88',
   122→  p89 = 'p89',
   123→  p90 = 'p90',
   124→  p91 = 'p91',
   125→  p92 = 'p92',
   126→  p93 = 'p93',
   127→  p94 = 'p94',
   128→  p95 = 'p95',
   129→  p96 = 'p96',
   130→  p97 = 'p97',
   131→  p98 = 'p98',
   132→  p99 = 'p99',
   133→}
   134→
   135→export function getFieldTypeForReducer(id: ReducerID, fallback: FieldType): FieldType {
   136→  return id === ReducerID.count ||
   137→    id === ReducerID.distinctCount ||
   138→    id === ReducerID.changeCount ||
   139→    id === ReducerID.countAll
   140→    ? FieldType.number
   141→    : id === ReducerID.allIsNull || id === ReducerID.allIsZero
   142→      ? FieldType.boolean
   143→      : fallback;
   144→}
   145→
   146→export function isReducerID(id: string): id is ReducerID {
   147→  return Object.keys(ReducerID).includes(id);
   148→}
   149→
   150→// Internal function
   151→type FieldReducer = (field: Field, ignoreNulls: boolean, nullAsZero: boolean) => FieldCalcs;
   152→
   153→export interface FieldReducerInfo extends RegistryItem {
   154→  // Internal details
   155→  emptyInputResult?: unknown; // typically null, but some things like 'count' & 'sum' should be zero
   156→  standard: boolean; // The most common stats can all be calculated in a single pass
   157→  preservesUnits: boolean; // Whether this reducer preserves units, certain ones don't e.g. count, distinct count, etc,
   158→  reduce?: FieldReducer;
   159→}
   160→
   161→interface ReduceFieldOptions {
   162→  field: Field;
   163→  reducers: string[]; // The stats to calculate
   164→}
   165→
   166→/**
   167→ * @returns an object with a key for each selected stat
   168→ * NOTE: This will also modify the 'field.state' object,
   169→ * leaving values in a cache until cleared.
   170→ */
   171→export function reduceField(options: ReduceFieldOptions): FieldCalcs {
   172→  const { field, reducers } = options;
   173→
   174→  if (!field || !reducers || reducers.length < 1) {
   175→    return {};
   176→  }
   177→
   178→  if (field.state?.calcs) {
   179→    // Find the values we need to calculate
   180→    const missing: string[] = [];
   181→    for (const s of reducers) {
   182→      if (!field.state.calcs.hasOwnProperty(s)) {
   183→        missing.push(s);
   184→      }
   185→    }
   186→    if (missing.length < 1) {
   187→      return {
   188→        ...field.state.calcs,
   189→      };
   190→    }
   191→  }
   192→  if (!field.state) {
   193→    field.state = {};
   194→  }
   195→
   196→  const queue = fieldReducers.list(reducers);
   197→
   198→  // Return early for empty series
   199→  // This lets the concrete implementations assume at least one row
   200→  const data = field.values;
   201→  if (data && data.length < 1) {
   202→    const calcs: FieldCalcs = { ...field.state.calcs };
   203→    for (const reducer of queue) {
   204→      calcs[reducer.id] = reducer.emptyInputResult !== null ? reducer.emptyInputResult : null;
   205→    }
   206→    return (field.state.calcs = calcs);
   207→  }
   208→
   209→  // Default to Ignore for nullValueMode.
   210→  const { nullValueMode = NullValueMode.Ignore } = field.config;
   211→
   212→  const ignoreNulls = nullValueMode === NullValueMode.Ignore;
   213→  const nullAsZero = nullValueMode === NullValueMode.AsZero;
   214→
   215→  // Avoid calculating all the standard stats if possible
   216→  if (queue.length === 1 && queue[0].reduce) {
   217→    const values = queue[0].reduce(field, ignoreNulls, nullAsZero);
   218→    field.state.calcs = {
   219→      ...field.state.calcs,
   220→      ...values,
   221→    };
   222→    return values;
   223→  }
   224→
   225→  // For now everything can use the standard stats
   226→  let values = doStandardCalcs(field, ignoreNulls, nullAsZero);
   227→
   228→  for (const reducer of queue) {
   229→    if (!values.hasOwnProperty(reducer.id) && reducer.reduce) {
   230→      values = {
   231→        ...values,
   232→        ...reducer.reduce(field, ignoreNulls, nullAsZero),
   233→      };
   234→    }
   235→  }
   236→
   237→  field.state.calcs = {
   238→    ...field.state.calcs,
   239→    ...values,
   240→  };
   241→  return values;
   242→}
   243→
   244→// ------------------------------------------------------------------------------
   245→//
   246→//  No Exported symbols below here.
   247→//
   248→// ------------------------------------------------------------------------------
   249→
   250→export const fieldReducers = new Registry<FieldReducerInfo>(() => [
   251→  {
   252→    id: ReducerID.lastNotNull,
   253→    name: 'Last *',
   254→    description: 'Last non-null value (also excludes NaNs)',
   255→    standard: true,
   256→    aliasIds: ['current'],
   257→    reduce: calculateLastNotNull,
   258→    preservesUnits: true,
   259→  },
   260→  {
   261→    id: ReducerID.last,
   262→    name: 'Last',
   263→    description: 'Last value',
   264→    standard: true,
   265→    reduce: calculateLast,
   266→    preservesUnits: true,
   267→  },
   268→  {
   269→    id: ReducerID.firstNotNull,
   270→    name: 'First *',
   271→    description: 'First non-null value (also excludes NaNs)',
   272→    standard: true,
   273→    reduce: calculateFirstNotNull,
   274→    preservesUnits: true,
   275→  },
   276→  {
   277→    id: ReducerID.first,
   278→    name: 'First',
   279→    description: 'First Value',
   280→    standard: true,
   281→    reduce: calculateFirst,
   282→    preservesUnits: true,
   283→  },
   284→  { id: ReducerID.min, name: 'Min', description: 'Minimum Value', standard: true, preservesUnits: true },
   285→  { id: ReducerID.max, name: 'Max', description: 'Maximum Value', standard: true, preservesUnits: true },
   286→  {
   287→    id: ReducerID.mean,
   288→    name: 'Mean',
   289→    description: 'Average Value',
   290→    standard: true,
   291→    aliasIds: ['avg'],
   292→    preservesUnits: true,
   293→  },
   294→  {
   295→    id: ReducerID.median,
   296→    name: 'Median',
   297→    description: 'Median Value',
   298→    standard: false,
   299→    reduce: calculateMedian,
   300→    aliasIds: ['median'],
   301→    preservesUnits: true,
   302→  },
   303→  {
   304→    id: ReducerID.variance,
   305→    name: 'Variance',
   306→    description: 'Variance of all values in a field',
   307→    standard: false,
   308→    reduce: calculateStdDev,
   309→    preservesUnits: true,
   310→  },
   311→  {
   312→    id: ReducerID.stdDev,
   313→    name: 'StdDev',
   314→    description: 'Standard deviation of all values in a field',
   315→    standard: false,
   316→    reduce: calculateStdDev,
   317→    preservesUnits: true,
   318→  },
   319→  {
   320→    id: ReducerID.sum,
   321→    name: 'Total',
   322→    description: 'The sum of all values',
   323→    emptyInputResult: 0,
   324→    standard: true,
   325→    aliasIds: ['total'],
   326→    preservesUnits: true,
   327→  },
   328→  {
   329→    id: ReducerID.count,
   330→    name: 'Count',
   331→    description: 'Number of values in response',
   332→    emptyInputResult: 0,
   333→    standard: true,
   334→    preservesUnits: false,
   335→  },
   336→  {
   337→    id: ReducerID.countAll,
   338→    name: 'Count all',
   339→    description: 'Number of values (including empty)',
   340→    emptyInputResult: 0,
   341→    standard: false,
   342→    reduce: (field: Field): FieldCalcs => ({ countAll: field.values.length }),
   343→    preservesUnits: false,
   344→  },
   345→  {
   346→    id: ReducerID.range,
   347→    name: 'Range',
   348→    description: 'Difference between minimum and maximum values',
   349→    standard: true,
   350→    preservesUnits: true,
   351→  },
   352→  {
   353→    id: ReducerID.delta,
   354→    name: 'Delta',
   355→    description: 'Cumulative change in value',
   356→    standard: true,
   357→    preservesUnits: true,
   358→  },
   359→  {
   360→    id: ReducerID.step,
   361→    name: 'Step',
   362→    description: 'Minimum interval between values',
   363→    standard: true,
   364→    preservesUnits: true,
   365→  },
   366→  {
   367→    id: ReducerID.diff,
   368→    name: 'Difference',
   369→    description: 'Difference between first and last values',
   370→    standard: true,
   371→    preservesUnits: true,
   372→  },
   373→  {
   374→    id: ReducerID.logmin,
   375→    name: 'Min (above zero)',
   376→    description: 'Used for log min scale',
   377→    standard: true,
   378→    preservesUnits: true,
   379→  },
   380→  {
   381→    id: ReducerID.allIsZero,
   382→    name: 'All Zeros',
   383→    description: 'All values are zero',
   384→    emptyInputResult: false,
   385→    standard: true,
   386→    preservesUnits: true,
   387→  },
   388→  {
   389→    id: ReducerID.allIsNull,
   390→    name: 'All Nulls',
   391→    description: 'All values are null',
   392→    emptyInputResult: true,
   393→    standard: true,
   394→    preservesUnits: false,
   395→  },
   396→  {
   397→    id: ReducerID.changeCount,
   398→    name: 'Change Count',
   399→    description: 'Number of times the value changes',
   400→    standard: false,
   401→    reduce: calculateChangeCount,
   402→    preservesUnits: false,
   403→  },
   404→  {
   405→    id: ReducerID.distinctCount,
   406→    name: 'Distinct Count',
   407→    description: 'Number of distinct values',
   408→    standard: false,
   409→    reduce: calculateDistinctCount,
   410→    preservesUnits: false,
   411→  },
   412→  {
   413→    id: ReducerID.diffperc,
   414→    name: 'Difference percent',
   415→    description: 'Percentage difference between first and last values',
   416→    standard: true,
   417→    preservesUnits: false,
   418→  },
   419→  {
   420→    id: ReducerID.allValues,
   421→    name: 'All values',
   422→    description: 'Returns an array with all values',
   423→    standard: false,
   424→    reduce: (field: Field) => ({ allValues: [...field.values] }),
   425→    preservesUnits: false,
   426→  },
   427→  {
   428→    id: ReducerID.uniqueValues,
   429→    name: 'All unique values',
   430→    description: 'Returns an array with all unique values',
   431→    standard: false,
   432→    reduce: (field: Field) => ({
   433→      uniqueValues: [...new Set(field.values)],
   434→    }),
   435→    preservesUnits: false,
   436→  },
   437→  ...buildPercentileReducers(),
   438→]);
   439→
   440→// This `Array.from` will build an array of elements from 1 to 99
   441→const buildPercentileReducers = (percentiles = [...Array.from({ length: 99 }, (_, i) => i + 1)]) => {
   442→  const percentileReducers: FieldReducerInfo[] = [];
   443→  const nth = (n: number) =>
   444→    n > 3 && n < 21 ? 'th' : n % 10 === 1 ? 'st' : n % 10 === 2 ? 'nd' : n % 10 === 3 ? 'rd' : 'th';
   445→
   446→  percentiles.forEach((p) => {
   447→    const percentile = p / 100;
   448→    const id = `p${p}`;
   449→    const name = `${p}${nth(p)} %`;
   450→    const description = `${p}${nth(p)} percentile value`;
   451→
   452→    percentileReducers.push({
   453→      id: id,
   454→      name: name,
   455→      description: description,
   456→      standard: false,
   457→      reduce: (field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs => {
   458→        return { [id]: calculatePercentile(field, percentile, ignoreNulls, nullAsZero) };
   459→      },
   460→      preservesUnits: true,
   461→    });
   462→  });
   463→  return percentileReducers;
   464→};
   465→
   466→// Used for test cases
   467→export const defaultCalcs: FieldCalcs = {
   468→  sum: 0,
   469→  max: -Number.MAX_VALUE,
   470→  min: Number.MAX_VALUE,
   471→  logmin: Number.MAX_VALUE,
   472→  mean: null,
   473→  last: null,
   474→  first: null,
   475→  lastNotNull: null,
   476→  firstNotNull: null,
   477→  count: 0,
   478→  nonNullCount: 0,
   479→  allIsNull: true,
   480→  allIsZero: true,
   481→  range: null,
   482→  diff: null,
   483→  delta: 0,
   484→  step: Number.MAX_VALUE,
   485→  diffperc: 0,
   486→  // Just used for calculations -- not exposed as a stat
   487→  previousDeltaUp: true,
   488→};
   489→
   490→export function doStandardCalcs(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   491→  const calcs: FieldCalcs = { ...defaultCalcs };
   492→
   493→  const data = field.values;
   494→
   495→  // early return for undefined / empty series
   496→  if (!data) {
   497→    return calcs;
   498→  }
   499→
   500→  const isNumberField = field.type === FieldType.number || field.type === FieldType.time;
   501→
   502→  for (let i = 0; i < data.length; i++) {
   503→    let currentValue = data[i];
   504→
   505→    if (i === 0) {
   506→      calcs.first = currentValue;
   507→    }
   508→
   509→    calcs.last = currentValue;
   510→
   511→    if (currentValue == null) {
   512→      if (ignoreNulls) {
   513→        continue;
   514→      }
   515→      if (nullAsZero) {
   516→        currentValue = 0;
   517→      }
   518→    }
   519→
   520→    calcs.count++;
   521→
   522→    if (currentValue != null && !Number.isNaN(currentValue)) {
   523→      // null || undefined || NaN
   524→      const isFirst = calcs.firstNotNull === null;
   525→      if (isFirst) {
   526→        calcs.firstNotNull = currentValue;
   527→      }
   528→
   529→      if (isNumberField) {
   530→        calcs.sum += currentValue || 0;
   531→        calcs.allIsNull = false;
   532→        calcs.nonNullCount++;
   533→
   534→        if (!isFirst) {
   535→          const step = currentValue - calcs.lastNotNull!;
   536→          if (calcs.step > step) {
   537→            calcs.step = step; // the minimum interval
   538→          }
   539→
   540→          if (calcs.lastNotNull! > currentValue) {
   541→            // counter reset
   542→            calcs.previousDeltaUp = false;
   543→          } else {
   544→            if (calcs.previousDeltaUp) {
   545→              calcs.delta += step; // normal increment
   546→            }
   547→            calcs.previousDeltaUp = true;
   548→          }
   549→        }
   550→
   551→        if (currentValue > calcs.max) {
   552→          calcs.max = currentValue;
   553→        }
   554→
   555→        if (currentValue < calcs.min) {
   556→          calcs.min = currentValue;
   557→        }
   558→
   559→        if (currentValue < calcs.logmin && currentValue > 0) {
   560→          calcs.logmin = currentValue;
   561→        }
   562→      }
   563→
   564→      if (currentValue !== 0) {
   565→        calcs.allIsZero = false;
   566→      }
   567→
   568→      calcs.lastNotNull = currentValue;
   569→    }
   570→  }
   571→
   572→  if (calcs.max === -Number.MAX_VALUE) {
   573→    calcs.max = null;
   574→  }
   575→
   576→  if (calcs.min === Number.MAX_VALUE) {
   577→    calcs.min = null;
   578→  }
   579→
   580→  if (calcs.step === Number.MAX_VALUE) {
   581→    calcs.step = null;
   582→  }
   583→
   584→  if (calcs.nonNullCount > 0) {
   585→    calcs.mean = calcs.sum! / calcs.nonNullCount;
   586→  }
   587→
   588→  if (calcs.allIsNull) {
   589→    calcs.allIsZero = false;
   590→  }
   591→
   592→  if (calcs.max !== null && calcs.min !== null) {
   593→    calcs.range = calcs.max - calcs.min;
   594→  }
   595→
   596→  if (isNumber(calcs.firstNotNull) && isNumber(calcs.lastNotNull)) {
   597→    calcs.diff = calcs.lastNotNull - calcs.firstNotNull;
   598→  }
   599→
   600→  if (isNumber(calcs.firstNotNull) && isNumber(calcs.diff)) {
   601→    calcs.diffperc = (calcs.diff / calcs.firstNotNull) * 100;
   602→  }
   603→
   604→  return calcs;
   605→}
   606→
   607→function calculateFirst(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   608→  return { first: field.values[0] };
   609→}
   610→
   611→function calculateFirstNotNull(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   612→  const data = field.values;
   613→  for (let idx = 0; idx < data.length; idx++) {
   614→    const v = data[idx];
   615→    if (v != null && !Number.isNaN(v)) {
   616→      return { firstNotNull: v };
   617→    }
   618→  }
   619→  return { firstNotNull: null };
   620→}
   621→
   622→function calculateLast(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   623→  const data = field.values;
   624→  return { last: data[data.length - 1] };
   625→}
   626→
   627→function calculateLastNotNull(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   628→  const data = field.values;
   629→  let idx = data.length - 1;
   630→  while (idx >= 0) {
   631→    const v = data[idx--];
   632→    if (v != null && !Number.isNaN(v)) {
   633→      return { lastNotNull: v };
   634→    }
   635→  }
   636→  return { lastNotNull: null };
   637→}
   638→
   639→/** Calculates standard deviation and variance */
   640→function calculateStdDev(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   641→  // Only support number fields
   642→  if (!(field.type === FieldType.number || field.type === FieldType.time)) {
   643→    return { variance: 0, stdDev: 0 };
   644→  }
   645→
   646→  let squareSum = 0;
   647→  let runningMean = 0;
   648→  let runningNonNullCount = 0;
   649→  const data = field.values;
   650→  for (let i = 0; i < data.length; i++) {
   651→    const currentValue = data[i];
   652→    if (currentValue != null) {
   653→      runningNonNullCount++;
   654→      let _oldMean = runningMean;
   655→      runningMean += (currentValue - _oldMean) / runningNonNullCount;
   656→      squareSum += (currentValue - _oldMean) * (currentValue - runningMean);
   657→    }
   658→  }
   659→  if (runningNonNullCount > 0) {
   660→    const variance = squareSum / runningNonNullCount;
   661→    return { variance, stdDev: Math.sqrt(variance) };
   662→  }
   663→  return { variance: 0, stdDev: 0 };
   664→}
   665→
   666→function calculateChangeCount(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   667→  const data = field.values;
   668→  let count = 0;
   669→  let first = true;
   670→  let last = null;
   671→  for (let i = 0; i < data.length; i++) {
   672→    let currentValue = data[i];
   673→    if (currentValue === null) {
   674→      if (ignoreNulls) {
   675→        continue;
   676→      }
   677→      if (nullAsZero) {
   678→        currentValue = 0;
   679→      }
   680→    }
   681→    if (!first && last !== currentValue) {
   682→      count++;
   683→    }
   684→    first = false;
   685→    last = currentValue;
   686→  }
   687→
   688→  return { changeCount: count };
   689→}
   690→
   691→function calculateDistinctCount(field: Field, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   692→  const data = field.values;
   693→  const distinct = new Set();
   694→  for (let i = 0; i < data.length; i++) {
   695→    let currentValue = data[i];
   696→    if (currentValue === null) {
   697→      if (ignoreNulls) {
   698→        continue;
   699→      }
   700→      if (nullAsZero) {
   701→        currentValue = 0;
   702→      }
   703→    }
   704→    distinct.add(currentValue);
   705→  }
   706→  return { distinctCount: distinct.size };
   707→}
   708→
   709→function calculatePercentile(field: Field, percentile: number, ignoreNulls: boolean, nullAsZero: boolean): number {
   710→  let data = field.values;
   711→
   712→  if (ignoreNulls) {
   713→    data = data.filter((value) => value !== null);
   714→  }
   715→  if (nullAsZero) {
   716→    data = data.map((value) => (value === null ? 0 : value));
   717→  }
   718→
   719→  const sorted = data.slice().sort((a, b) => a - b);
   720→  const index = Math.round((sorted.length - 1) * percentile);
   721→  return sorted[index];
   722→}
   723→
   724→function calculateMedian(field: Field<number>, ignoreNulls: boolean, nullAsZero: boolean): FieldCalcs {
   725→  const numbers: number[] = [];
   726→
   727→  for (let i = 0; i < field.values.length; i++) {
   728→    let currentValue = field.values[i];
   729→
   730→    if (currentValue == null) {
   731→      if (ignoreNulls) {
   732→        continue;
   733→      }
   734→      if (nullAsZero) {
   735→        currentValue = 0;
   736→      }
   737→    }
   738→
   739→    numbers.push(currentValue);
   740→  }
   741→
   742→  numbers.sort((a, b) => a - b);
   743→
   744→  const mid = Math.floor(numbers.length / 2);
   745→
   746→  if (numbers.length % 2 === 0) {
   747→    return { median: (numbers[mid - 1] + numbers[mid]) / 2 };
   748→  } else {
   749→    return { median: numbers[mid] };
   750→  }
   751→}
